import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"38G. Reproductive Health Leave","description":"","frontmatter":{"title":"38G. Reproductive Health Leave","eba":"Mental Health Services 2024-2028","topics":["leave","reproductive-health-leave","preliminary","definitions"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/38G-reproductive-health-leave.md","filePath":"ebas/mental-health/common-terms/leave/38G-reproductive-health-leave.md"}'),s={name:"ebas/mental-health/common-terms/leave/38G-reproductive-health-leave.md"};function n(i,e,l,p,c,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_38g-reproductive-health-leave" tabindex="-1">38G. Reproductive Health Leave <a class="header-anchor" href="#_38g-reproductive-health-leave" aria-label="Permalink to &quot;38G. Reproductive Health Leave&quot;">​</a></h1><p>Note: This clause does not apply to casual employees.</p><p><strong>38G.1</strong> Definition:</p><p><strong>(a)</strong> For the purposes of this clause, reproductive health matter includes polycystic ovarian syndrome, endometriosis and assisted reproduction.</p><p><strong>38G.2</strong> Entitlement</p><p><strong>(a)</strong> An Employee may take up to five days (pro-rata for part-time Employees) per year of service paid Reproductive Health where an Employee:</p><p><strong>(i)</strong> Is unable to work as a result of experiencing symptoms associated with endometriosis or polycystic ovarian syndrome; or</p><p><strong>(ii)</strong> Requires medical care for treatment of, or associated with, endometriosis or polycystic ovary syndrome; or</p><p><strong>(iii)</strong> Is undertaking a medical procedure associated with assisted reproduction.</p><p><strong>38G.3</strong> Access to Reproductive Health Leave An Employee will become eligible to access the five days of Reproductive Health Leave where their balance of accrued Personal Leave has reduced to fifteen days or fewer. Subject to the conditions in this clause, a maximum of five days leave will be available per each year of employment. Accrual of Personal Leave will not be affected or reduced by an Employee accessing Reproductive Health and Wellbeing Leave.</p><p><strong>38G.4</strong> Notice and evidence requirements:</p><p><strong>(a)</strong> The employee shall give the employer notice as soon as reasonably practicable when accessing leave under this clause.</p><p><strong>(b)</strong> If required by the employer, the employee is to provide evidence that would satisfy a reasonable person that leave taken under this clause was for a purpose described at 38G.2.</p><p><strong>38G.5</strong> Flexible working arrangements: Employees may seek to access reasonable adjustments as per <a href="/eba/ebas/mental-health/common-terms/workplace-rights/67-reasonable-adjustments-for-employees-with-a-disability.html">clause 67</a> and flexible working arrangements as per <a href="/eba/ebas/mental-health/common-terms/workplace-rights/65-flexible-working-arrangements.html">clause 65</a>, in conjunction with this clause.</p><p>38H Rehabilitation Leave Note: This clause does not apply to casual Employees.</p><p><strong>38H.1</strong> Paid Leave to Attend a Rehabilitation Program An Employee may be granted up to maximum 30 days of paid Rehabilitation Leave over the life of this Agreement to attend an alcohol and other drug treatment program(s), which may include a residential and/or hospital-based withdrawal/detox program(s) and/or rehabilitation program(s).</p><p><strong>38H.2</strong> Evidence</p><p><strong>(a)</strong> To access Rehabilitation Leave, the Employee must provide the Employer evidence of enrolment and the program attendance requirements prior to the commencement of the program. The Employer may also require evidence of ongoing attendance at the program.</p><p><strong>(b)</strong> If required by the Employer, the Employee is to provide evidence that would satisfy a reasonable person that the leave taken under this clause will be for the purpose described at 38H.1.</p><p><strong>38H.3</strong> Use of paid Rehabilitation Leave</p><p><strong>(a)</strong> An Employee may utilise leave under this clause in conjunction with any other type of leave.</p><p><strong>(b)</strong> An Employee is not required to exhaust other forms of paid leave before they can access paid leave under this clause.</p><p><strong>(c)</strong> Leave under this clause will not break (and will count towards) an Employee’s continuous service.</p><p>Plain language terms: period leave, period pain, menstrual leave, menstruation, IVF, fertility, miscarriage, menopause, endometriosis.</p>',24)])])}const u=a(s,[["render",n]]);export{h as __pageData,u as default};
